# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.

SECURITY REQUIREMENTS:

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.

SECURE (DO THIS):

- Allowlist valid hosts, paths, and route patterns before navigating.
- Authorize access to privileged screens such as admin or payment flows after parsing the link.
- Validate and normalize IDs/parameters before using them.

INSECURE (NEVER DO THIS):

- Do not trust any path or parameter from a deep link or universal link without validation.
- Do not let deep links directly open privileged screens without server-side or app-side authorization checks.
- Do not register overly broad handlers that process arbitrary URLs.
# Category: insecure_universal_links

import UIKit

struct PromoLink {
    let code: String
    let discount: Int
    let isValid: Bool
}

class PromoLinkHandler {
    static let shared = PromoLinkHandler()
    
    private let validHosts = ["myapp.com"]
    private let validPaths = ["/promo"]
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return false
        }
        
        // Validate host
        guard let host = components.host, validHosts.contains(host) else {
            return false
        }
        
        // Validate path
        guard let path = components.path, validPaths.contains(path) else {
            return false
        }
        
        // Extract and validate parameters
        guard let promoCode = components.queryItems?.first(where: { $0.name == "code" })?.value,
              let discountString = components.queryItems?.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString),
              discount >= 0 && discount <= 100 else {
            return false
        }
        
        // Normalize and validate promo code
        let normalizedCode = promoCode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedCode.isEmpty else {
            return false
        }
        
        let promoLink = PromoLink(code: normalizedCode, discount: discount, isValid: true)
        applyPromoCode(promoLink)
        return true
    }
    
    private func applyPromoCode(_ promoLink: PromoLink) {
        // Validate promo code with server
        validateAndApplyPromoCode(promoLink.code, discount: promoLink.discount)
    }
    
    private func validateAndApplyPromoCode(_ code: String, discount: Int) {
        // Simulate server validation
        DispatchQueue.main.async {
            // Show promo applied alert
            let alert = UIAlertController(
                title: "Promo Applied",
                message: "You've received a \(discount)% discount with code \(code)",
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            
            if let scene = UIApplication.shared.connectedScenes.first,
               let windowScene = scene as? UIWindowScene,
               let window = windowScene.windows.first {
                window.rootViewController?.present(alert, animated: true)
            }
        }
    }
}

extension AppDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            return PromoLinkHandler.shared.handleUniversalLink(url)
        }
        return false
    }
}

// In your SceneDelegate or SceneDelegate.swift
class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            _ = PromoLinkHandler.shared.handleUniversalLink(url)
        }
    }
}